/**
 * Agroconnect – Dashboard "Fresh Picks" Product Section
 * ─────────────────────────────────────────────────────────────────
 * INSTALL: Code Snippets → Add New → Run Everywhere → Save & Activate
 *
 * USAGE:  Add the shortcode  [agro_fresh_picks]  anywhere on your
 *         My Account page (or any page/widget).
 *
 * HOW IT WORKS:
 *  • Renders the latest X WooCommerce products in a styled grid
 *  • "Add to Basket" uses WooCommerce's native AJAX add-to-cart
 *    so the cart fragment (header counter) updates instantly
 *  • A mini toast notification confirms each addition
 *  • Works with any theme – no template overrides needed
 * ─────────────────────────────────────────────────────────────────
 */

/* ── 1. Register shortcode ───────────────────────────────────────── */
add_shortcode( 'agro_fresh_picks', 'agro_fresh_picks_shortcode' );

function agro_fresh_picks_shortcode( $atts ) {
    $atts = shortcode_atts( array(
        'limit'    => 8,       // how many products to show
        'columns'  => 4,       // grid columns (desktop)
        'category' => '',      // optional: slug of a product category
        'title'    => 'Fresh Picks',
    ), $atts, 'agro_fresh_picks' );

    if ( ! class_exists( 'WooCommerce' ) ) {
        return '<p style="color:#c00;">WooCommerce is not active.</p>';
    }

    /* ── Query products ── */
    $args = array(
        'post_type'      => 'product',
        'post_status'    => 'publish',
        'posts_per_page' => intval( $atts['limit'] ),
        'orderby'        => 'date',
        'order'          => 'DESC',
        'meta_query'     => array(
            array(
                'key'     => '_stock_status',
                'value'   => 'instock',
                'compare' => '=',
            ),
        ),
    );

    if ( ! empty( $atts['category'] ) ) {
        $args['tax_query'] = array(
            array(
                'taxonomy' => 'product_cat',
                'field'    => 'slug',
                'terms'    => sanitize_text_field( $atts['category'] ),
            ),
        );
    }

    $products = new WP_Query( $args );

    if ( ! $products->have_posts() ) {
        return '<p style="font-family:sans-serif;color:#888;padding:20px 0;">No products found.</p>';
    }

    /* ── Cart URL ── */
    $cart_url     = wc_get_cart_url();
    $checkout_url = wc_get_checkout_url();

    ob_start();
    ?>

