    <script>
    (function () {
        'use strict';

        var AJAX_URL  = '<?php echo esc_js( admin_url('admin-ajax.php') ); ?>';
        var CART_URL  = '<?php echo esc_js( $cart_url ); ?>';
        var toastEl   = document.getElementById('agfp-toast');
        var toastName = document.getElementById('agfp-toast-product');
        var toastTimer;

        /* ── Show toast ── */
        function showToast(name) {
            if (!toastEl || !toastName) return;
            toastName.textContent = name;
            toastEl.classList.add('show');
            clearTimeout(toastTimer);
            toastTimer = setTimeout(function () {
                toastEl.classList.remove('show');
            }, 4000);
        }

        /* ── Update every cart count element on the page ── */
        function updateCartCount(count) {
            /* WooCommerce themes expose cart count in various selectors */
            var selectors = [
                '.cart-contents-count',
                '.cart_count',
                '.count',
                '.header-cart-count',
                '.wc-cart-count',
                '[class*="cart"][class*="count"]',
                '[class*="basket"][class*="count"]',
                '.menu-item .cart-count',
                'span.cart-items-count',
                'a.cart-contents span',
            ];
            var found = false;
            selectors.forEach(function (sel) {
                try {
                    document.querySelectorAll(sel).forEach(function (el) {
                        el.textContent = count;
                        el.classList.remove('agfp-cart-pop');
                        void el.offsetWidth; // reflow to restart animation
                        el.classList.add('agfp-cart-pop');
                        found = true;
                    });
                } catch(e){}
            });

            /* Fallback: refresh WC cart fragments via AJAX */
            if (!found) {
                refreshCartFragments();
            }
        }

        /* ── Refresh WooCommerce cart fragments (updates mini-cart) ── */
        function refreshCartFragments() {
            if (typeof jQuery === 'undefined') return;
            jQuery(document.body).trigger('wc_fragment_refresh');
            /* Also trigger the standard WC event so themes that
               listen to it (e.g. Flatsome, Astra, OceanWP) update */
            jQuery(document.body).trigger('added_to_cart', [{}]);
        }

        /* ── AJAX add to cart ── */
        function addToCart(btn) {
            var productId   = btn.getAttribute('data-product-id');
            var productName = btn.getAttribute('data-product-name');
            var nonce       = btn.getAttribute('data-nonce');

            if (!productId) return;

            /* Loading state */
            btn.classList.add('loading');
            btn.disabled = true;

            var formData = new FormData();
            formData.append('action',     'agro_ajax_add_to_cart');
            formData.append('product_id', productId);
            formData.append('quantity',   1);
            formData.append('nonce',      nonce);

            fetch(AJAX_URL, {
                method:      'POST',
                credentials: 'same-origin',
                body:        formData,
            })
            .then(function (res) {
                if (!res.ok) throw new Error('Network error: ' + res.status);
                return res.json();
            })
            .then(function (data) {
                btn.classList.remove('loading');

                if (data.success) {
                    /* ── Success ── */
                    btn.classList.add('added');
                    var svg = btn.querySelector('svg');
                    var txt = btn.querySelector('.agfp-btn-text');
                    if (svg) svg.innerHTML = '<polyline points="20 6 9 17 4 12"/>';
                    if (txt) txt.textContent = 'Added!';

                    /* Update cart count badge */
                    if (data.cart_count !== undefined) {
                        updateCartCount(data.cart_count);
                    }

                    /* Trigger WooCommerce fragment refresh */
                    refreshCartFragments();

                    /* Show toast */
                    showToast(productName);

                    /* Reset button after 3 s */
                    setTimeout(function () {
                        btn.classList.remove('added');
                        btn.disabled = false;
                        if (svg) svg.innerHTML =
                            '<path d="M6 2 3 6v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2V6l-3-4z"/>' +
                            '<line x1="3" y1="6" x2="21" y2="6"/>' +
                            '<path d="M16 10a4 4 0 0 1-8 0"/>';
                        if (txt) txt.textContent = 'Add to Basket';
                    }, 3000);

                } else {
                    /* ── Error returned from server ── */
                    btn.disabled = false;
                    var txt = btn.querySelector('.agfp-btn-text');
                    if (txt) txt.textContent = data.message || 'Try again';
                    setTimeout(function () {
                        btn.classList.remove('loading');
                        if (txt) txt.textContent = 'Add to Basket';
                        btn.disabled = false;
                    }, 2500);
                }
            })
            .catch(function (err) {
                btn.classList.remove('loading');
                btn.disabled = false;
                console.error('[Agro AJAX]', err);
                var txt = btn.querySelector('.agfp-btn-text');
                if (txt) { txt.textContent = 'Error — try again'; }
                setTimeout(function () {
                    if (txt) txt.textContent = 'Add to Basket';
                }, 2500);
            });
        }

        /* ── Attach click handlers ── */
        document.querySelectorAll('.agfp-add-to-cart').forEach(function (btn) {
            btn.addEventListener('click', function (e) {
                e.preventDefault();
                addToCart(btn);
            });
        });

        /* ── Dismiss toast on click ── */
        if (toastEl) {
            toastEl.addEventListener('click', function (e) {
                if (!e.target.closest('.agfp-toast-cta')) {
                    toastEl.classList.remove('show');
                }
            });
        }

    })();
    </script>
