/* ── 2. AJAX handler (logged-in AND guest users) ─────────────────── */
add_action( 'wp_ajax_agro_ajax_add_to_cart',        'agro_ajax_add_to_cart_handler' );
add_action( 'wp_ajax_nopriv_agro_ajax_add_to_cart', 'agro_ajax_add_to_cart_handler' );

function agro_ajax_add_to_cart_handler() {

    /* Verify nonce */
    $product_id = isset( $_POST['product_id'] ) ? absint( $_POST['product_id'] ) : 0;
    $nonce      = isset( $_POST['nonce'] )       ? sanitize_text_field( $_POST['nonce'] ) : '';

    if ( ! $product_id || ! wp_verify_nonce( $nonce, 'agro_add_to_cart_' . $product_id ) ) {
        wp_send_json_error( array( 'message' => 'Security check failed.' ) );
    }

    $quantity = isset( $_POST['quantity'] ) ? absint( $_POST['quantity'] ) : 1;
    if ( $quantity < 1 ) $quantity = 1;

    /* Verify product exists and is in stock */
    $product = wc_get_product( $product_id );
    if ( ! $product || ! $product->is_purchasable() || ! $product->is_in_stock() ) {
        wp_send_json_error( array( 'message' => 'Product unavailable.' ) );
    }

    /* Add to WooCommerce cart */
    $added = WC()->cart->add_to_cart( $product_id, $quantity );

    if ( $added ) {
        WC()->cart->calculate_totals();

        wp_send_json_success( array(
            'message'    => 'Added to cart.',
            'cart_count' => WC()->cart->get_cart_contents_count(),
            'cart_total' => WC()->cart->get_cart_total(),
        ) );
    } else {
        wp_send_json_error( array( 'message' => 'Could not add to basket. Please try again.' ) );
    }
}


