add_action( 'init', 'agro_ensure_wc_session' );
function agro_ensure_wc_session() {
    if ( is_admin() ) return;
    if ( isset( WC()->session ) && ! WC()->session->has_session() ) {
        WC()->session->set_customer_session_cookie( true );
    }
}
